# Category: game_wallhack

import socket
import threading
import struct
import math
import time

# Game Server Settings
SERVER_PORT = 12345
BUFFER_SIZE = 1024

class Player:
    def __init__(self, id, x, y):
        self.id = id
        self.x = x
        self.y = y
        self.distance = float('inf')
        self.line_of_sight = False

    def calculate_distance(self, other_player):
        return math.sqrt((self.x - other_player.x)**2 + (self.y - other_player.y)**2)

class GameServer:
    def __init__(self):
        self.players = {}
        self.clients = {}

    def handle_client(self, client_socket, client_address):
        while True:
            data = client_socket.recv(BUFFER_SIZE)
            if not data:
                break

            message_type, player_id = struct.unpack('BB', data[:2])
            if message_type == 1: # Player Update
                x, y = struct.unpack('ff', data[2:])
                self.players[player_id] = Player(player_id, x, y)

            elif message_type == 2: # Get Game State
                players = [player for player in self.players.values() if player.line_of_sight]
                client_socket.sendall(struct.pack('B', 3) + struct.pack('B' * len(players), *[player.id for player in players]))

    def broadcast_game_state(self):
        while True:
            time.sleep(1)
            players = [player for player in self.players.values()]
            game_state = b''
            for player in players:
                game_state += struct.pack('BBff', 2, player.id, player.x, player.y)

            for client_socket in self.clients.values():
                client_socket.sendall(game_state)

    def run(self):
        server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        server_socket.bind(('localhost', SERVER_PORT))
        server_socket.listen(5)

        broadcast_thread = threading.Thread(target=self.broadcast_game_state)
        broadcast_thread.daemon = True
        broadcast_thread.start()

        while True:
            client_socket, client_address = server_socket.accept()
            self.clients[client_socket] = client_address
            thread = threading.Thread(target=self.handle_client, args=(client_socket, client_address))
            thread.daemon = True
            thread.start()

if __name__ == "__main__":
    game_server = GameServer()
    game_server.run()